import { useState, useMemo } from "react";
import { Outlet, useNavigate, Link, useLocation } from "react-router-dom";
import { authService } from "@/App";
import { Button } from "@/components/ui/button";
import {
  LayoutDashboard, Users, UsersRound, CreditCard, CalendarCheck,
  GraduationCap, Calendar, Package, LogOut, Menu, X, Building2,
  Bell, User, FileText
} from "lucide-react";

const DashboardLayout = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const user = authService.getUser();

  const handleLogout = () => {
    authService.clearAuth();
    navigate("/login");
  };

  // ✅ ALL HOOKS FIRST (NO CONDITIONAL LOGIC BEFORE THIS)
  const menuItems = [
    { icon: LayoutDashboard, label: "Dashboard", path: "/app/dashboard", roles: ["super_admin", "school_admin", "teacher", "finance", "secretary"] },
    { icon: Building2, label: "Super Admin", path: "/app/super-admin", roles: ["super_admin"] },
    { icon: Building2, label: "School Profile", path: "/app/school-profile", roles: ["school_admin"] },
    { icon: Users, label: "Students", path: "/app/students", roles: ["school_admin", "teacher"] },
    { icon: UsersRound, label: "Staff", path: "/app/staff", roles: ["school_admin"] },
    { icon: CreditCard, label: "Fees", path: "/app/fees", roles: ["school_admin", "finance"] },
    { icon: CalendarCheck, label: "Attendance", path: "/app/attendance", roles: ["school_admin", "teacher"] },
    { icon: GraduationCap, label: "Performance", path: "/app/exams", roles: ["school_admin", "teacher"] },
    { icon: Bell, label: "Announcements", path: "/app/announcements", roles: ["school_admin", "teacher", "secretary"] },
    { icon: User, label: "Teacher Portal", path: "/app/teacher-portal", roles: ["teacher"] },
    { icon: CreditCard, label: "Finance Portal", path: "/app/finance-portal", roles: ["finance"] },
    { icon: FileText, label: "Secretary Portal", path: "/app/secretary-portal", roles: ["secretary"] },
    { icon: User, label: "Student Portal", path: "/app/student-portal", roles: ["student", "parent"] },
    { icon: Calendar, label: "Timetable", path: "/app/timetable", roles: ["school_admin", "teacher"] },
    { icon: Package, label: "Inventory", path: "/app/inventory", roles: ["school_admin"] },
  ];

  // ✅ SAFE FILTER (NO HOOK RULE VIOLATION)
  const visibleItems = useMemo(() => {
    if (!user?.role) return [];
    return menuItems.filter(item => item.roles.includes(user.role));
  }, [user]);

  const isActive = (path) =>
    location.pathname === path || location.pathname.startsWith(path);

  return (
    <div className="flex h-screen bg-[#0B1120]">

      {/* Sidebar */}
      <aside
        className={`fixed lg:static inset-y-0 left-0 z-50 w-64 bg-[#111827] border-r border-[#1E293B] transform transition-transform duration-200 ${
          sidebarOpen ? "translate-x-0" : "-translate-x-full lg:translate-x-0"
        }`}
      >

        {/* Logo */}
        <div className="h-16 flex items-center justify-between px-5 border-b border-[#1E293B]">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-emerald-600 rounded-lg flex items-center justify-center">
              <GraduationCap className="w-5 h-5 text-white" />
            </div>
            <span className="text-lg font-bold text-white">Smart-M Hub</span>
          </div>

          <button
            className="lg:hidden text-slate-400 hover:text-white"
            onClick={() => setSidebarOpen(false)}
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Nav */}
        <nav className="p-3 space-y-1 overflow-y-auto">
          {visibleItems.map(item => {
            const Icon = item.icon;

            return (
              <Link
                key={item.path}
                to={item.path}
                onClick={() => setSidebarOpen(false)}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm ${
                  isActive(item.path)
                    ? "bg-emerald-600/15 text-emerald-400"
                    : "text-slate-400 hover:text-slate-200 hover:bg-[#1A2332]"
                }`}
              >
                <Icon className="w-[18px] h-[18px]" />
                <span>{item.label}</span>
              </Link>
            );
          })}
        </nav>

        {/* User */}
        <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-[#1E293B]">
          <p className="text-sm text-white">{user?.full_name}</p>
          <p className="text-xs text-slate-500">{user?.email}</p>

          <Button
            variant="ghost"
            className="w-full justify-start text-red-400 mt-3"
            onClick={handleLogout}
          >
            <LogOut className="w-4 h-4 mr-2" />
            Logout
          </Button>
        </div>
      </aside>

      {/* Main */}
      <div className="flex-1 flex flex-col">
        <header className="h-14 bg-[#111827] border-b border-[#1E293B] flex items-center justify-between px-5">

          <button
            className="lg:hidden text-slate-400 hover:text-white"
            onClick={() => setSidebarOpen(true)}
          >
            <Menu className="w-5 h-5" />
          </button>

          <h1 className="text-slate-300">Welcome, {user?.full_name}</h1>

          <span className="text-xs text-emerald-400 uppercase">
            {user?.role?.replace("_", " ")}
          </span>
        </header>

        <main className="flex-1 p-5 overflow-auto">
          <Outlet />
        </main>
      </div>
    </div>
  );
};

export default DashboardLayout;
